/**
 * Denial Logger — PermissionDenied Hook
 *
 * Writes an audit trail of all permission denials to
 * .claude/feedback/permission-denials.jsonl (one JSON object per line).
 *
 * Sync — writes to disk on each denial. Never returns retry.
 *
 * CC 2.1.88 Compliant: PermissionDenied hook
 * @hook PermissionDenied (sync)
 * @since v7.27.0
 * @see #1208
 */

import { existsSync, mkdirSync, appendFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import type { HookInput, HookResult , HookContext} from '../types.js';
import { outputSilentSuccess, getProjectDir } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'denial-logger';

function getDenialLogPath(): string {
  const projectDir = getProjectDir();
  return join(projectDir, '.claude', 'feedback', 'permission-denials.jsonl');
}

export function denialLogger(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  try {
    const logPath = getDenialLogPath();
    const logDir = dirname(logPath);

    if (!existsSync(logDir)) {
      mkdirSync(logDir, { recursive: true });
    }

    const entry = {
      timestamp: new Date().toISOString(),
      session_id: input.session_id || 'unknown',
      tool_name: input.tool_name || 'unknown',
      tool_input_summary: summarizeInput(input),
    };

    appendFileSync(logPath, `${JSON.stringify(entry)}\n`, 'utf-8');
    ctx.log(HOOK_NAME, `Logged denial for ${entry.tool_name}`);
  } catch (error) {
    const msg = error instanceof Error ? error.message : String(error);
    ctx.log(HOOK_NAME, `Failed to log denial: ${msg}`, 'warn');
  }

  // Never retry — logger is observation-only
  return outputSilentSuccess();
}

/**
 * Produce a safe summary of the denied tool input (no secrets).
 */
function summarizeInput(input: HookInput): string {
  const toolInput = input.tool_input || {};

  if (toolInput.command) {
    // Bash: truncate command, scrub potential secrets (SEC-005)
    let cmd = String(toolInput.command).slice(0, 200);
    // Redact common secret patterns: tokens, passwords, API keys
    cmd = cmd.replace(/(?:password|token|key|secret|auth|bearer)\s*[=:]\s*\S+/gi, `${'$&'.split('=')[0]}=***`);
    cmd = cmd.replace(/([-]-(?:password|token|key|secret)[\s=])\S+/gi, '$1***');
    cmd = cmd.replace(/\b[A-Za-z0-9_]{20,}(?=\s|$)/g, (m) => m.length > 30 ? `${m.slice(0, 8)}***` : m);
    return `command: ${cmd}`;
  }

  if (toolInput.file_path) {
    return `file_path: ${toolInput.file_path}`;
  }

  return 'unknown input';
}
